@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="dropZoneRef" class="drop-zone @(isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in files)
        {
            <li class="file-entry @(entry.Error is not null ? "file-error" : "")">
                <div class="file-info">
                    @if (entry.Error is not null)
                    {
                        <span class="error-message">@entry.Info.Name &mdash; @entry.Error</span>
                    }
                    else
                    {
                        <span class="file-name">@entry.Info.Name</span>
                        <span class="file-meta">@FormatSize(entry.Info.Size) &middot; @entry.Info.Type</span>
                    }
                </div>
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxSizeBytes = 10 * 1024 * 1024;

    private ElementReference dropZoneRef;
    private IJSObjectReference? module;
    private DotNetObjectReference<FileDropZone>? dotNetRef;
    private bool isDragOver;
    private readonly List<FileEntry> files = new();

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import", "./Components/FileDropZone.razor.js");
            dotNetRef = DotNetObjectReference.Create(this);
            await module.InvokeVoidAsync("initDropZone", dropZoneRef, dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragOverChanged(bool over)
    {
        isDragOver = over;
        StateHasChanged();
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileEntry[] droppedFiles)
    {
        isDragOver = false;

        foreach (var f in droppedFiles)
        {
            if (f.Info.Size > MaxSizeBytes)
            {
                f.Error = $"File exceeds 10 MB limit ({FormatSize(f.Info.Size)})";
            }
        }

        files.AddRange(droppedFiles);
        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        files.Remove(entry);
        await NotifyParent();
    }

    private Task NotifyParent()
    {
        var accepted = files.Where(f => f.Error is null).Select(f => f.Info).ToList();
        return OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("dispose", dropZoneRef);
            await module.DisposeAsync();
        }
        dotNetRef?.Dispose();
    }

    public class FileEntry
    {
        public FileInfo Info { get; set; } = default!;
        public string? Error { get; set; }
    }
}

const zones = new Map();

export function initDropZone(element, dotNetRef) {
    function onDragEnter(e) {
        e.preventDefault();
        dotNetRef.invokeMethodAsync('OnDragOverChanged', true);
    }

    function onDragOver(e) {
        e.preventDefault();
    }

    function onDragLeave(e) {
        if (!element.contains(e.relatedTarget)) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    }

    function onDrop(e) {
        e.preventDefault();
        const files = [];
        for (const file of e.dataTransfer.files) {
            files.push({
                info: { name: file.name, size: file.size, type: file.type || 'application/octet-stream' },
                error: null
            });
        }
        dotNetRef.invokeMethodAsync('OnFilesDropped', files);
    }

    element.addEventListener('dragenter', onDragEnter);
    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    zones.set(element, { onDragEnter, onDragOver, onDragLeave, onDrop });
}

export function dispose(element) {
    const handlers = zones.get(element);
    if (handlers) {
        element.removeEventListener('dragenter', handlers.onDragEnter);
        element.removeEventListener('dragover', handlers.onDragOver);
        element.removeEventListener('dragleave', handlers.onDragLeave);
        element.removeEventListener('drop', handlers.onDrop);
        zones.delete(element);
    }
}

.drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 2rem;
    text-align: center;
    color: #6c757d;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-info {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
}

.file-name {
    font-weight: 500;
}

.file-meta {
    font-size: 0.85rem;
    color: #6c757d;
}

.error-message {
    color: #dc3545;
    font-weight: 500;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.75rem;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: white;
}

