@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="dropZoneRef" class="drop-zone @(isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in files)
        {
            <li class="file-entry @(entry.Error is not null ? "file-error" : "")">
                <div class="file-info">
                    @if (entry.Error is not null)
                    {
                        <span class="error-message">@entry.Info.Name &mdash; @entry.Error</span>
                    }
                    else
                    {
                        <span class="file-name">@entry.Info.Name</span>
                        <span class="file-meta">@FormatSize(entry.Info.Size) &middot; @entry.Info.Type</span>
                    }
                </div>
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxSizeBytes = 10 * 1024 * 1024;

    private ElementReference dropZoneRef;
    private IJSObjectReference? module;
    private DotNetObjectReference<FileDropZone>? dotNetRef;
    private bool isDragOver;
    private readonly List<FileEntry> files = new();

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import", "./Components/FileDropZone.razor.js");
            dotNetRef = DotNetObjectReference.Create(this);
            await module.InvokeVoidAsync("initDropZone", dropZoneRef, dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragOverChanged(bool over)
    {
        isDragOver = over;
        StateHasChanged();
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileEntry[] droppedFiles)
    {
        isDragOver = false;

        foreach (var f in droppedFiles)
        {
            if (f.Info.Size > MaxSizeBytes)
            {
                f.Error = $"File exceeds 10 MB limit ({FormatSize(f.Info.Size)})";
            }
        }

        files.AddRange(droppedFiles);
        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        files.Remove(entry);
        await NotifyParent();
    }

    private Task NotifyParent()
    {
        var accepted = files.Where(f => f.Error is null).Select(f => f.Info).ToList();
        return OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("dispose", dropZoneRef);
            await module.DisposeAsync();
        }
        dotNetRef?.Dispose();
    }

    public class FileEntry
    {
        public FileInfo Info { get; set; } = default!;
        public string? Error { get; set; }
    }
}

